preprocess.style:
({ content, filename }) => {
      if (files.find((file) => filename.endsWith(file))) {
        const code = content.replaceAll(
          /([0-9.]+)r?em/g,
          (_, value) => `${parseFloat(value) * 16}px`
        );
        return { code };
      }
    }

preprocess.markup:
({ content, filename }) => {
      if (filename.endsWith("src/map/Map.svelte")) {
        const code = content.replaceAll(/^.*customElement=".*$/gm, "");
        return { code };
      }
    }
